package main

import (
	"fmt"
	"strings"

	"github.com/goccy/go-yaml"
)

type Default struct {
	Key string `yaml:"key"`
}

type Test struct {
	First    string  `yaml:"first"`
	Defaults Default `yaml:"second"`
}

func main() {
	yml := `first: "Test"
second:
  # Just want to document the fields of the nested struct
#  key: "Value from YAML"
`

	test := Test{Defaults: Default{Key: "My default Value"}}
	fmt.Printf("Before decode: test.Defaults.Key = %q\n", test.Defaults.Key)

	d := yaml.NewDecoder(strings.NewReader(yml))
	err := d.Decode(&test)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("After decode: test.Defaults.Key = %q\n", test.Defaults.Key)
	if test.Defaults.Key == "My default Value" {
		fmt.Println("PASS: Default value preserved")
	} else {
		fmt.Println("FAIL: Default value lost")
	}
}

