	"testing"

	"github.com/goccy/go-yaml"
)

type Default struct {
	Key string `yaml:"key"`
}

type TestDefaults struct {
	First    string  `yaml:"first"`
	Defaults Default `yaml:"second"`
}

func TestPreserveDefaultsWithNullNode(t *testing.T) {
	yml := `first: "Test"
second:
  # Just want to document the fields of the nested struct
#  key: "Value from YAML"
`

	test := TestDefaults{Defaults: Default{Key: "My default Value"}}
	d := yaml.NewDecoder(strings.NewReader(yml))
	err := d.Decode(&test)
	if err != nil {
		t.Fatalf("failed to decode %v", err)
	}

	if test.Defaults.Key != "My default Value" {
		t.Fatalf("expected to preserve default value, but got %q", test.Defaults.Key)
	}
}
