	// Test: Deeply nested structures with defaults
	yml := `middle:
  # Just a comment
  # inner:
  #   value: "test"
`
	innerDefault := &Inner{Value: "inner_default"}
	middleDefault := &Middle{Inner: innerDefault}
	test := Outer{Middle: middleDefault}

	d := yaml.NewDecoder(strings.NewReader(yml))
	err := d.Decode(&test)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
	}

	if test.Middle != nil && test.Middle.Inner != nil && test.Middle.Inner.Value == "inner_default" {
		fmt.Println("✓ Deeply nested structures with defaults work")
	} else {
		if test.Middle == nil {
			fmt.Println("✗ Middle is nil")
		} else if test.Middle.Inner == nil {
			fmt.Println("✗ Inner is nil")
		} else {
			fmt.Printf("✗ Value is %q\n", test.Middle.Inner.Value)
		}
	}
}
EOF
